import 'dart:io'; import 'package:cloud_firestore/cloud_firestore.dart'; import '../../../../core/constants/firestore_collections.dart'; import '../../../../core/constants/storage_paths.dart'; import '../../../../core/services/firebase/firestore_service.dart'; import '../../../../core/services/firebase/storage_service.dart'; import '../../domain/entities/report.dart'; import '../../domain/repositories/report_repository.dart';
class ReportRepositoryImpl implements ReportRepository{final FirestoreService fs; final StorageService storage; const ReportRepositoryImpl({required FirestoreService firestoreService,required StorageService storageService}):fs=firestoreService,storage=storageService; CollectionReference<Map<String,dynamic>> get reports=>fs.collection(FirestoreCollections.reports); @override Stream<List<Report>> watchMyReports({required String reporterId})=>reports.where('reporterId',isEqualTo:reporterId).orderBy('createdAt',descending:true).snapshots().map((s)=>s.docs.map((d)=>Report.fromMap(d.id,d.data())).toList()); @override Stream<List<Report>> watchPendingReports()=>reports.where('status',isEqualTo:ReportStatus.pending.name).orderBy('createdAt',descending:true).snapshots().map((s)=>s.docs.map((d)=>Report.fromMap(d.id,d.data())).toList()); @override Future<Report?> getReport(String id) async{final d=await reports.doc(id).get(); return d.exists&&d.data()!=null?Report.fromMap(d.id,d.data()!):null;} @override Future<String> createReport({required String reporterId,required String targetId,required ReportTargetType targetType,required ReportReason reason,required String description,List<File> evidenceImages=const[]}) async{final doc=reports.doc(); final urls=<String>[]; for(var i=0;i<evidenceImages.length;i++){urls.add(await storage.uploadFile(file:evidenceImages[i],path:StoragePaths.reportEvidence(reporterId:reporterId,reportId:doc.id,fileName:'${DateTime.now().millisecondsSinceEpoch}_$i.jpg'),contentType:'image/jpeg'));} await doc.set({'reporterId':reporterId,'targetId':targetId,'targetType':targetType.name,'reason':reason.name,'status':ReportStatus.pending.name,'description':description,'evidenceImageUrls':urls,'createdAt':FieldValue.serverTimestamp(),'updatedAt':FieldValue.serverTimestamp()}); return doc.id;} @override Future<void> updateReportStatus({required String reportId,required ReportStatus status,required String adminId,String? adminNote})=>reports.doc(reportId).update({'status':status.name,'reviewedBy':adminId,'adminNote':adminNote,'reviewedAt':FieldValue.serverTimestamp(),'updatedAt':FieldValue.serverTimestamp()}); @override Future<void> deleteReport({required String reportId})=>reports.doc(reportId).delete();}
